}
.login-right .sub { color: var(--gray-500); font-size: 0.9rem; margin-bottom: 2rem; }
.login-hint {
  background: var(--blue-light);
  border: 1px solid #bfdbfe;
  border-radius: 8px;
  padding: 0.75rem 1rem;
  font-size: 0.8rem;
  color: var(--blue);
  margin-top: 1.25rem;
  text-align: center;
}
.login-hint strong { font-weight: 700; }

/* ── TOAST ── */
.toast {
  position: fixed;
  bottom: 2rem;
  right: 2rem;
  z-index: 9999;
  padding: 1rem 1.5rem;
  border-radius: 12px;
  font-size: 0.88rem;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  box-shadow: var(--shadow-lg);
  animation: slideUp 0.3s ease;
  max-width: 360px;
}
.toast-success { background: #166534; color: white; border: 1px solid #22c55e; }
.toast-error   { background: #7f1d1d; color: white; border: 1px solid #ef4444; }
.toast-warn    { background: #78350f; color: white; border: 1px solid #f59e0b; }

/* ── EMPTY STATE ── */
.empty-state {
  padding: 4rem 2rem;
  text-align: center;
  color: var(--gray-400);
}
.empty-state .es-icon { font-size: 3rem; margin-bottom: 1rem; opacity: 0.5; }
.empty-state p { font-size: 0.9rem; }

/* ── FOOTER ── */
.footer {
  background: var(--gray-900);
  color: var(--gray-400);
  text-align: center;
  padding: 1.25rem;
  font-size: 0.8rem;
  margin-top: 4rem;
}
.footer span { color: var(--coral); }

/* ── ANIMATIONS ── */
@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}
.page { animation: slideUp 0.3s ease; }

/* ── RESPONSIVE ── */
@media (max-width: 1024px) {
  .stats-row, .action-grid { grid-template-columns: repeat(2, 1fr); }
  .login-split { width: 95vw; }
}
@media (max-width: 700px) {
  .stats-row, .action-grid { grid-template-columns: 1fr; }
  .login-split { flex-direction: column; }
  .login-left { padding: 2rem; min-height: 200px; }
  .nav-search { display: none; }
  .catbar { display: none; }
}
